#include <iostream>
#include <vector>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    // We need a up to n, allocate n+1
    vector<int> a(n + 1);
    a[0] = 1;
    if (n >= 1) a[1] = 1;

    for (int i = 2; i <= n; ++i) {
        if (i % 2 == 0) {
            // i = 2k  => a[i] = a[k] + 1
            int k = i / 2;
            a[i] = a[k] + 1;
        } else {
            // i = 2k+1  => use a[2k+2] = a[2k+1] - a[k]
            // but we need a[i] where i is odd: i = 2k+1
            // from the recurrence a[2k+2] = a[2k+1] - a[k]
            // => a[i] = a[i+1] + a[(i-1)/2]  but i+1 may be > n...
            // Let's derive directly.
            // i = 2k+1. The recurrence for a[2k+2] involves a[2k+1].
            // Rearranging: a[2k+1] = a[2k+2] + a[k]
            // But a[2k+2] = a[k+1] + 1 (since 2k+2 = 2(k+1))
            // So a[i] = a[k+1] + 1 + a[k]
            int k = i / 2; // integer division, for i=2k+1 this gives k
            a[i] = a[k+1] + 1 + a[k];
        }
    }

    cout << a[n] << "\n";
    return 0;
}
